"""Tests for the first-class geopandas API: pandera.geopandas."""

import geopandas as gpd
import pandas as pd
import pytest
from pydantic import BaseModel, ValidationError
from shapely.geometry import Point, Polygon

import pandera.geopandas as pag
from pandera.engines.geopandas_engine import Geometry
from pandera.errors import SchemaError, SchemaErrors
from pandera.typing import Series
from pandera.typing.geopandas import GeoDataFrame, GeoSeries

UNIT_SQUARE = Polygon(((0, 0), (0, 1), (1, 1), (1, 0)))
BIG_SQUARE = Polygon(((0, 0), (0, 2), (2, 2), (2, 0)))


def sample_gdf(crs="EPSG:4326") -> gpd.GeoDataFrame:
    return gpd.GeoDataFrame(
        {
            "geometry": gpd.GeoSeries([UNIT_SQUARE, BIG_SQUARE], crs=crs),
            "name": ["a", "b"],
        },
        crs=crs,
    )


def test_import_surface():
    """The geopandas module exposes the same ergonomics as pandera.pandas."""
    for attr in [
        "GeoDataFrameSchema",
        "GeoDataFrameModel",
        "Column",
        "Index",
        "MultiIndex",
        "Check",
        "Field",
        "check",
        "dataframe_check",
        "infer_schema",
        "Geometry",
        "errors",
    ]:
        assert hasattr(pag, attr), f"pandera.geopandas missing {attr}"


class TestGeoDataFrameSchema:
    """Object-based API."""

    def test_validate_returns_geodataframe_with_crs(self):
        schema = pag.GeoDataFrameSchema(
            {
                "geometry": pag.Column("geometry"),
                "name": pag.Column(str),
            }
        )
        validated = schema.validate(sample_gdf())
        assert isinstance(validated, gpd.GeoDataFrame)
        assert isinstance(validated["geometry"].dtype, gpd.array.GeometryDtype)
        assert validated.crs == "EPSG:4326"
        # active geometry column preserved so geospatial ops work downstream
        assert validated.geometry.name == "geometry"
        assert (validated.area > 0).all()

    def test_validate_upgrades_plain_dataframe(self):
        """A plain pandas DataFrame comes back as a GeoDataFrame."""
        schema = pag.GeoDataFrameSchema(
            {"geometry": pag.Column(Geometry, coerce=True)}
        )
        df = pd.DataFrame({"geometry": gpd.GeoSeries([UNIT_SQUARE])})
        assert not isinstance(df, gpd.GeoDataFrame)
        validated = schema.validate(df)
        assert isinstance(validated, gpd.GeoDataFrame)
        assert validated.geometry.name == "geometry"

    def test_validate_coerces_wkt(self):
        schema = pag.GeoDataFrameSchema(
            {"geometry": pag.Column(Geometry, coerce=True)}
        )
        df = pd.DataFrame({"geometry": ["POINT (0 0)", "POINT (1 1)"]})
        validated = schema.validate(df)
        assert isinstance(validated, gpd.GeoDataFrame)
        assert (validated.geometry == gpd.GeoSeries([Point(0, 0), Point(1, 1)])).all()

    def test_validate_failure_raises_schema_error(self):
        schema = pag.GeoDataFrameSchema(
            {
                "geometry": pag.Column(
                    "geometry",
                    checks=pag.Check(lambda s: s.area >= 2),
                ),
                "name": pag.Column(str),
            }
        )
        with pytest.raises(SchemaError):
            schema.validate(sample_gdf())

    def test_validate_failure_lazy_raises_schema_errors(self):
        schema = pag.GeoDataFrameSchema(
            {
                "geometry": pag.Column(
                    "geometry",
                    checks=pag.Check(lambda s: s.area >= 2),
                ),
                "name": pag.Column(int),
            }
        )
        with pytest.raises(SchemaErrors):
            schema.validate(sample_gdf(), lazy=True)

    def test_missing_column_raises(self):
        schema = pag.GeoDataFrameSchema(
            {
                "geometry": pag.Column("geometry"),
                "missing": pag.Column(str),
            }
        )
        with pytest.raises(SchemaError):
            schema.validate(sample_gdf())

    def test_schema_callable_returns_geodataframe(self):
        schema = pag.GeoDataFrameSchema({"geometry": pag.Column("geometry")})
        assert isinstance(schema(sample_gdf()), gpd.GeoDataFrame)


class TestGeoDataFrameModel:
    """Class-based API."""

    def test_model_validate_returns_geodataframe(self):
        class Schema(pag.GeoDataFrameModel):
            geometry: GeoSeries
            name: Series[str] = pag.Field(isin=["a", "b"])

        validated = Schema.validate(sample_gdf())
        assert isinstance(validated, gpd.GeoDataFrame)
        assert validated.crs == "EPSG:4326"
        assert validated.geometry.name == "geometry"

    def test_model_to_schema_is_geo_schema(self):
        class Schema(pag.GeoDataFrameModel):
            geometry: GeoSeries

        assert isinstance(Schema.to_schema(), pag.GeoDataFrameSchema)

    def test_model_custom_check(self):
        class Schema(pag.GeoDataFrameModel):
            geometry: GeoSeries

            @pag.check("geometry")
            @classmethod
            def area_check(cls, geo_series: GeoSeries) -> Series[bool]:
                return geo_series.area >= 2

        with pytest.raises(SchemaError):
            Schema.validate(sample_gdf())

        valid = gpd.GeoDataFrame({"geometry": gpd.GeoSeries([BIG_SQUARE])})
        assert isinstance(Schema.validate(valid), gpd.GeoDataFrame)

    def test_model_config_coerce_upgrades_plain_dataframe(self):
        class Schema(pag.GeoDataFrameModel):
            geometry: GeoSeries

            class Config:
                coerce = True

        df = pd.DataFrame({"geometry": ["POINT (0 0)"]})
        validated = Schema.validate(df)
        assert isinstance(validated, gpd.GeoDataFrame)

    def test_model_field_failure(self):
